const e=JSON.parse('{"key":"v-6cae9def","path":"/mk-framework/module/guide/","title":"新手引导","lang":"zh-CN","frontmatter":{"title":"新手引导","article":false,"timeline":false,"dir":{"order":4,"index":true},"description":"新手引导系统是 MKFramework 中用于创建和管理游戏内新手引导流程的工具。它允许开发者设计步骤式的交互教程，帮助玩家熟悉游戏的操作和功能，它的新手引导系统有以下几个亮点： 🔄多实例支持：MKFramework的新手引导系统支持创建多个引导实例，允许开发者同时管理多个引导流程。 ➕步骤插入与删除：该引导系统支持在任意阶段插入或删除步骤，提供了灵活的引导流程控制。 ⏸️暂停与完成操作：开发者可以根据游戏逻辑需要，随时暂停或完成新手引导，以适应玩家的行为。 🔄状态还原：当引导跳转到任意步骤后，系统支持状态还原，确保玩家可以继续引导而不会感到困惑。 🔧步骤脚本分离：引导步骤脚本是分离的，支持组件式挂载，这意味着每个步骤可以独立编写和管理，使得引导流程的修改和扩展变得更加简单。 🧩组件化：引导功能被设计为组件化，可以轻松地集成到游戏项目中，且不会和游戏本身的其他部分产生耦合。 这些特点使得MKFramework的新手引导系统既灵活又强大，能够帮助开发者创建出符合不同游戏需求的引导流程。","head":[["meta",{"property":"og:url","content":"https://muzzik.gitee.io/mk-framework/module/guide/"}],["meta",{"property":"og:site_name","content":"MKSite"}],["meta",{"property":"og:title","content":"新手引导"}],["meta",{"property":"og:description","content":"新手引导系统是 MKFramework 中用于创建和管理游戏内新手引导流程的工具。它允许开发者设计步骤式的交互教程，帮助玩家熟悉游戏的操作和功能，它的新手引导系统有以下几个亮点： 🔄多实例支持：MKFramework的新手引导系统支持创建多个引导实例，允许开发者同时管理多个引导流程。 ➕步骤插入与删除：该引导系统支持在任意阶段插入或删除步骤，提供了灵活的引导流程控制。 ⏸️暂停与完成操作：开发者可以根据游戏逻辑需要，随时暂停或完成新手引导，以适应玩家的行为。 🔄状态还原：当引导跳转到任意步骤后，系统支持状态还原，确保玩家可以继续引导而不会感到困惑。 🔧步骤脚本分离：引导步骤脚本是分离的，支持组件式挂载，这意味着每个步骤可以独立编写和管理，使得引导流程的修改和扩展变得更加简单。 🧩组件化：引导功能被设计为组件化，可以轻松地集成到游戏项目中，且不会和游戏本身的其他部分产生耦合。 这些特点使得MKFramework的新手引导系统既灵活又强大，能够帮助开发者创建出符合不同游戏需求的引导流程。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-04-10T03:20:02.000Z"}],["meta",{"property":"article:author","content":"muzzik"}],["meta",{"property":"article:modified_time","content":"2024-04-10T03:20:02.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"新手引导\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2024-04-10T03:20:02.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"muzzik\\"}]}"]]},"headers":[{"level":2,"title":"API","slug":"api","link":"#api","children":[]}],"git":{"createdTime":1701161980000,"updatedTime":1712719202000,"contributors":[{"name":"muzzik","email":"1226085293@qq.com","commits":1},{"name":"yuanfengxin","email":"1226085293@qq.com","commits":1}]},"readingTime":{"minutes":1.42,"words":427},"filePathRelative":"mk-framework/module/guide/README.md","localizedDate":"2023年11月28日","excerpt":"<p>新手引导系统是 MKFramework 中用于创建和管理游戏内新手引导流程的工具。它允许开发者设计步骤式的交互教程，帮助玩家熟悉游戏的操作和功能，它的新手引导系统有以下几个亮点：</p>\\n<ul>\\n<li>\\n<p><strong>🔄多实例支持</strong>：MKFramework的新手引导系统支持创建多个引导实例，允许开发者同时管理多个引导流程。</p>\\n</li>\\n<li>\\n<p><strong>➕步骤插入与删除</strong>：该引导系统支持在任意阶段插入或删除步骤，提供了灵活的引导流程控制。</p>\\n</li>\\n<li>\\n<p><strong>⏸️暂停与完成操作</strong>：开发者可以根据游戏逻辑需要，随时暂停或完成新手引导，以适应玩家的行为。</p>\\n</li>\\n<li>\\n<p><strong>🔄状态还原</strong>：当引导跳转到任意步骤后，系统支持状态还原，确保玩家可以继续引导而不会感到困惑。</p>\\n</li>\\n<li>\\n<p><strong>🔧步骤脚本分离</strong>：引导步骤脚本是分离的，支持组件式挂载，这意味着每个步骤可以独立编写和管理，使得引导流程的修改和扩展变得更加简单。</p>\\n</li>\\n<li>\\n<p><strong>🧩组件化</strong>：引导功能被设计为组件化，可以轻松地集成到游戏项目中，且不会和游戏本身的其他部分产生耦合。</p>\\n</li>\\n</ul>\\n<p>这些特点使得MKFramework的新手引导系统既灵活又强大，能够帮助开发者创建出符合不同游戏需求的引导流程。</p>\\n","autoDesc":true}');export{e as data};
